records = [
  {"id":"inno_ent_351","name_ja":"サーキュラーエコノミー起業家精神","name_en":"Circular Economy Entrepreneurship","definition":"廃棄物ゼロ・資源循環を経済モデルの根幹に置くサーキュラーエコノミー（CE）の実現を担う起業家精神の研究。Ellen MacArthur Foundationが2013年に体系化したCEモデル（再生可能エネルギー使用・廃棄物設計除去・システム全体のパフォーマンス）への起業的対応が分析される。Repair Café、二次利用プラットフォーム（Back Market）、廃棄食材活用スタートアップが事例。","impact_summary":"線形経済（採掘→製造→廃棄）から循環経済への転換を推進する起業家の役割を理論化し、CE政策設計に貢献した。","subfield":"entrepreneurship_venture","category":"A_foundations","school_of_thought":"持続可能性起業家論","era_start":2013,"schumpeter_layer":"メゾ","innovation_type":"サーキュラーイノベーション","cognitive_mechanism":"廃棄物の価値転換と循環ビジネス設計","key_researchers":["Derk Loorbach","Ellen MacArthur Foundation","Jouni Korhonen"],"key_works":["Circular Economy (EMF 2013)","Circular Economy Entrepreneurship (2018)"],"keywords_ja":"サーキュラーエコノミー,循環起業家,廃棄物ゼロ,Back Market","keywords_en":"circular economy,circular entrepreneurship,zero waste,Back Market"},
  {"id":"inno_ent_352","name_ja":"バイオテックスタートアップ","name_en":"Biotech Startup Entrepreneurship","definition":"生命科学・バイオテクノロジーを基盤とするスタートアップの起業家精神研究。Genentech（1976）以来の産学連携型バイオベンチャー、CRISPRゲノム編集（Mammoth Biosciences、Editas）、mRNA（Moderna）、合成生物学（Ginkgo Bioworks）が代表例。長い開発期間（FDA承認15年以上）、高い失敗率（Phase III失敗率60%）、知財防衛戦略が独自の経営課題。","impact_summary":"生命科学のイノベーション商業化モデルを確立し、バイオVC生態系と大学発スタートアップ論を深化させた。","subfield":"entrepreneurship_venture","category":"B_systems","school_of_thought":"技術起業家論","era_start":1976,"schumpeter_layer":"ミクロ","innovation_type":"生命科学イノベーション","cognitive_mechanism":"科学的発見の商業化機会認識と長期コミットメント","key_researchers":["Gary Pisano","Henry Chesbrough","Iain Cockburn"],"key_works":["Science Business (2006)","The Pharmaceutical Innovation Shortfall (2011)"],"keywords_ja":"バイオテック,Moderna,CRISPR,FDA,産学連携","keywords_en":"biotech,Moderna,CRISPR,FDA,academic spinoff"},
  {"id":"inno_ent_353","name_ja":"ロボティクスとAIスタートアップ","name_en":"Robotics and AI Startup Entrepreneurship","definition":"ロボティクス・自律システム・AI技術を基盤とするスタートアップの起業家精神研究。Boston Dynamics、iRobot、UiPath（RPA）、Scale AI等が代表事例。ハードウェアとソフトウェアの複合的開発難易度、安全性・倫理的AI要件、産業用vs消費者向け市場戦略の選択が主要課題。Robotic VC（Lux Capital、DCVC）等の専門投資家生態系も研究される。","impact_summary":"自律システム技術の商業化エコシステムを整理し、ハードウェア×AI統合型スタートアップの経営論を提示した。","subfield":"entrepreneurship_venture","category":"B_systems","school_of_thought":"技術起業家論","era_start":2010,"schumpeter_layer":"ミクロ","innovation_type":"ロボティクス・AIイノベーション","cognitive_mechanism":"技術能力と市場ニーズの同期的発展","key_researchers":["Rodney Brooks","Astro Teller","Gill Pratt"],"key_works":["Startup Robotics (2019)","AI Startups Investment Report (2021)"],"keywords_ja":"ロボティクス,AI,自律システム,RPA,ハードウェアスタートアップ","keywords_en":"robotics,AI,autonomous systems,RPA,hardware startup"},
  {"id":"inno_ent_354","name_ja":"起業家的オポチュニティコスト","name_en":"Entrepreneurial Opportunity Cost","definition":"起業選択のオポチュニティコスト（機会費用）：高給与雇用の放棄・安定性の喪失・社会的期待の逸脱が起業意思決定に与える影響の研究。Hamilton（2000）は米国データで自営業者の生涯収入が雇用者より低いことを示し「起業家プレミアムの神話」を批判した。「非財務的リターン（自律性・アイデンティティ・達成感）」が財務的不利益を補う動機として研究される。","impact_summary":"起業の財務的コストとその心理的補償メカニズムを実証し、起業意思決定の総合的理解を深めた。","subfield":"entrepreneurship_venture","category":"A_foundations","school_of_thought":"実証的起業家研究","era_start":2000,"schumpeter_layer":"ミクロ","innovation_type":"経済学的起業家研究","cognitive_mechanism":"財務的期待効用と非財務的動機の統合計算","key_researchers":["Barton Hamilton","Erik Hurst","Annamaria Lusardi"],"key_works":["Does Entrepreneurship Pay? (2000)","Entrepreneurship and the Business Cycle (2011)"],"keywords_ja":"オポチュニティコスト,起業プレミアム,自律性動機,非財務リターン","keywords_en":"opportunity cost,entrepreneurship premium,autonomy motivation,non-financial return"},
  {"id":"inno_ent_355","name_ja":"起業家精神の地政学的側面","name_en":"Geopolitics of Entrepreneurship","definition":"地政学的競争（米中技術覇権争い、半導体サプライチェーン再編）がスタートアップエコシステムに与える影響の研究。CHIPsACT（米国2022）、欧州半導体法、中国の国家主導AI戦略が民間起業活動に与える影響。デュアルユース技術（軍民両用）スタートアップへの投資規制（CFIUS審査）、国家安全保障と起業家精神の緊張関係が研究される。","impact_summary":"起業家精神研究に地政学的視点を持ち込み、国家間技術競争の文脈でのスタートアップ政策を研究する新領域を開拓した。","subfield":"entrepreneurship_venture","category":"B_systems","school_of_thought":"政策的起業家論","era_start":2018,"schumpeter_layer":"マクロ","innovation_type":"地政学・安全保障イノベーション","cognitive_mechanism":"国家安全保障と商業動機の新たな統合","key_researchers":["Mariana Mazzucato","Robert Atkinson","Dani Rodrik"],"key_works":["The Entrepreneurial State (2013)","Innovation Mercantilism (2020)"],"keywords_ja":"地政学,技術覇権,CHIPS法,CFIUS,デュアルユース","keywords_en":"geopolitics,tech hegemony,CHIPS Act,CFIUS,dual-use"},
  {"id":"inno_ent_356","name_ja":"起業家精神とメンタルモデル","name_en":"Mental Models in Entrepreneurship","definition":"起業家が意思決定に使用する認知的枠組み（メンタルモデル）の研究。Senge（1990）のシステム思考メンタルモデルから、起業家固有の認知パターン（「私は解決策を作れる」「市場は変えられる」）まで分析される。思考の偏りとして「成功バイアス」「確証バイアス」「計画の誤謬」が起業的失敗に直結することが実証研究で示されている。","impact_summary":"起業家の認知的誤りを体系化し、デバイアスング訓練を組み込んだ起業家教育の設計に貢献した。","subfield":"entrepreneurship_venture","category":"A_foundations","school_of_thought":"認知的起業家論","era_start":2004,"schumpeter_layer":"ミクロ","innovation_type":"認知・行動イノベーション","cognitive_mechanism":"メンタルモデルによる選択的情報処理","key_researchers":["Phil Rosenzweig","Daniel Kahneman","Karl Weick"],"key_works":["The Halo Effect (2007)","Thinking, Fast and Slow (2011)"],"keywords_ja":"メンタルモデル,認知バイアス,計画の誤謬,確証バイアス","keywords_en":"mental models,cognitive bias,planning fallacy,confirmation bias"},
  {"id":"inno_ent_357","name_ja":"起業家精神の倫理的課題","name_en":"Ethical Issues in Entrepreneurship","definition":"起業家活動における倫理的意思決定の研究領域。「blitzscaling」に伴うルール無視（Uber、WeWork）、データプライバシー軽視（Facebook初期）、労働搾取（ギグワーカー）、誇大広告・投資家詐欺（Theranos）が重要ケース。起業家倫理の「利害関係者視点（Freeman）」対「株主至上主義（Friedman）」、倫理的ショートカットが長期的事業リスクとなる実証研究が蓄積されている。","impact_summary":"起業家倫理問題の体系化により、ガバナンス設計・投資家尽力義務・起業家教育への倫理カリキュラム組み込みを促した。","subfield":"entrepreneurship_venture","category":"A_foundations","school_of_thought":"批判的起業家論","era_start":2000,"schumpeter_layer":"ミクロ","innovation_type":"倫理・ガバナンスイノベーション","cognitive_mechanism":"倫理的ショートカットの認知的合理化","key_researchers":["R. Edward Freeman","Milton Snoeyenbos","Thomas Dean"],"key_works":["Ethical Dimensions of Entrepreneurship (2007)","Entrepreneurship Ethics: Values (2011)"],"keywords_ja":"起業家倫理,Theranos,Uber,データプライバシー,株主主権","keywords_en":"entrepreneurial ethics,Theranos,Uber,data privacy,stakeholder vs shareholder"},
  {"id":"inno_ent_358","name_ja":"起業家精神と宇宙経済","name_en":"Space Economy Entrepreneurship","definition":"宇宙の商業化・民営化による新経済圏（Space Economy）の起業家精神研究。Morgan Stanley推計では2040年に1.1兆ドル市場。衛星通信（Starlink）、宇宙旅行（Virgin Galactic）、軌道上製造、小惑星採掘が将来市場として研究される。SpaceXの再利用ロケットコスト革命が後続スタートアップの参入閾値を下げた効果分析が重要。","impact_summary":"宇宙を次の起業家フロンティアとして位置づけ、宇宙経済の産業構造と起業家機会の体系的研究を開始した。","subfield":"entrepreneurship_venture","category":"B_systems","school_of_thought":"技術起業家論","era_start":2015,"schumpeter_layer":"マクロ","innovation_type":"宇宙経済イノベーション","cognitive_mechanism":"超長期技術革新への起業家的コミットメント","key_researchers":["Elon Musk","Jeff Bezos","Namrata Goswami"],"key_works":["The Space Economy Report (Morgan Stanley 2020)","Who Owns the Moon? (2021)"],"keywords_ja":"宇宙経済,Starlink,宇宙旅行,小惑星採掘,Space Economy","keywords_en":"space economy,Starlink,space tourism,asteroid mining,commercial space"},
  {"id":"inno_ent_359","name_ja":"NFTと起業家精神","name_en":"NFT and Web3 Entrepreneurship","definition":"非代替性トークン（NFT）とWeb3（ブロックチェーン基盤の分散型インターネット）を活用した起業家精神の研究。OpenSea、Yuga Labs（BAYC）、スポーツNFT（NBA Top Shot）等が代表事例。DAO（分散型自律組織）を利用した新しいビジネス組織形態、クリエイターエコノミーへの応用、NFTバブルとその崩壊後のユーティリティNFTへの転換が研究される。","impact_summary":"ブロックチェーン技術が起業家の法人形態・資金調達・収益モデルに与えた変革を記述し、Web3起業家精神の独自論理を提示した。","subfield":"entrepreneurship_venture","category":"B_systems","school_of_thought":"フィンテック・Web3論","era_start":2021,"schumpeter_layer":"ミクロ","innovation_type":"デジタル資産イノベーション","cognitive_mechanism":"デジタル希少性と所有権の新しい経済学","key_researchers":["Primavera De Filippi","Aaron Wright","William Mougayar"],"key_works":["Blockchain and the Law (2018)","The Business Blockchain (2016)"],"keywords_ja":"NFT,Web3,DAO,クリエイターエコノミー,OpenSea","keywords_en":"NFT,Web3,DAO,creator economy,OpenSea"},
  {"id":"inno_ent_360","name_ja":"起業家精神とナレッジマネジメント","name_en":"Entrepreneurship and Knowledge Management","definition":"スタートアップにおける知識の創造・共有・活用・保護プロセスの研究。暗黙知（Polanyi/野中）の明示知化によるスケーリング、組織的知識創造の4段階モデル（SECI：社会化・外在化・結合化・内在化）の新興企業への適用、競合への知識流出防止（non-compete条項）が主要テーマ。Wikiスタイルのドキュメント文化がリモートスタートアップで標準化しつつある。","impact_summary":"知識管理をスタートアップの競争優位の中核に位置づけ、組織的学習理論の起業家研究への統合を促した。","subfield":"entrepreneurship_venture","category":"A_foundations","school_of_thought":"知識ベース論","era_start":1995,"schumpeter_layer":"ミクロ","innovation_type":"知識・学習イノベーション","cognitive_mechanism":"暗黙知の明示化と組織的知識循環","key_researchers":["Ikujiro Nonaka","Georg von Krogh","Hirotaka Takeuchi"],"key_works":["The Knowledge-Creating Company (1995)","Enabling Knowledge Creation (2000)"],"keywords_ja":"ナレッジマネジメント,SECI,暗黙知,スケーリング,ドキュメント文化","keywords_en":"knowledge management,SECI,tacit knowledge,scaling,documentation culture"},
  {"id":"inno_ent_361","name_ja":"危機におけるサバイバル起業家精神","name_en":"Survival Entrepreneurship in Crisis","definition":"経済危機・自然災害・戦争等の危機的状況下で生存手段として起業する「サバイバル起業家精神」の研究。ギリシャ債務危機（2010-2015）、シリア難民の起業、COVID-19後のジョブレス起業（unemployed founders）が研究事例。Williams & Nadin（2013）は危機が必要型起業を生み出し、一部が機会型起業へと転換するダイナミクスを分析した。","impact_summary":"危機環境での起業家精神の発生メカニズムを記述し、危機後の経済回復政策設計に起業支援を組み込む論拠を提供した。","subfield":"entrepreneurship_venture","category":"A_foundations","school_of_thought":"実証的起業家研究","era_start":2013,"schumpeter_layer":"ミクロ","innovation_type":"危機対応・レジリエンスイノベーション","cognitive_mechanism":"生存動機から機会認識への認知転換","key_researchers":["Colin Williams","Sara Nadin","Scott Shane"],"key_works":["Necessity-Driven Entrepreneurship (2013)","Entrepreneurship in Times of Crisis (2020)"],"keywords_ja":"サバイバル起業,危機,必要型起業,ジョブレス起業家,ギリシャ危機","keywords_en":"survival entrepreneurship,crisis,necessity-driven,jobless founder,Greek crisis"},
  {"id":"inno_ent_362","name_ja":"起業家精神と金融リテラシー","name_en":"Entrepreneurship and Financial Literacy","definition":"起業家の財務知識・スキルが事業の生存・成長に与える影響の研究。ColeとShastry（2010）は教育と金融リテラシーが起業選択と成功の強力な予測因子であることを示した。財務計画能力（キャッシュフロー管理、単位経済の理解）の欠如がスタートアップ失敗の構造的要因として識別される。起業家向け財務教育プログラムの設計・効果研究も進む。","impact_summary":"財務知識を起業家的成功の必要条件として定量化し、財務リテラシー教育を起業家支援プログラムに組み込む論拠を提供した。","subfield":"entrepreneurship_venture","category":"A_foundations","school_of_thought":"起業家教育論","era_start":2010,"schumpeter_layer":"ミクロ","innovation_type":"教育・財務イノベーション","cognitive_mechanism":"財務知識と資金管理行動の因果連鎖","key_researchers":["Shawn Cole","Anna Paulson","Martin Carree"],"key_works":["Financial Literacy, Entrepreneurship (2009)","Entrepreneurship and Firm Performance (2011)"],"keywords_ja":"財務リテラシー,起業家教育,キャッシュフロー,財務計画","keywords_en":"financial literacy,entrepreneurship education,cash flow,financial planning"},
  {"id":"inno_ent_363","name_ja":"起業家精神の時間的ダイナミクス","name_en":"Temporal Dynamics of Entrepreneurship","definition":"起業家活動の時間的変化パターン（季節性、業界サイクル、個人のライフステージ）を研究する領域。Bhide（2000）は多くのスタートアップが雇用期間中の「夜間・週末起業」から始まることを記述した。Lazear（2004）の「ジャックオブオールトレーズ」仮説は幅広い職業経験がタイミング選択を最適化することを示した。長期的エントレプレナーシップキャリアパターンも研究される。","impact_summary":"起業の時間的・ライフコース的文脈を明示化し、ライフステージ別の起業支援プログラムの設計に貢献した。","subfield":"entrepreneurship_venture","category":"A_foundations","school_of_thought":"ライフコース起業家論","era_start":2000,"schumpeter_layer":"ミクロ","innovation_type":"ライフコース・時間的イノベーション","cognitive_mechanism":"ライフステージと起業機会の認識タイミング","key_researchers":["Amar Bhide","Edward Lazear","Marc Cowling"],"key_works":["The Origin and Evolution of New Businesses (2000)","The Jack-of-All-Trades Entrepreneur (2004)"],"keywords_ja":"起業のタイミング,ライフステージ,ジャックオブオールトレーズ,副業起業","keywords_en":"entrepreneurship timing,life stage,jack-of-all-trades,side business"},
  {"id":"inno_ent_364","name_ja":"スタートアップエクイティ設計","name_en":"Startup Equity Design","definition":"創業者・従業員・投資家間の株式配分と権利設計の研究。Noam Wassermanの「創業者のジレンマ」研究は、株式配分決定が将来の紛争・離脱・業績に長期的影響を与えることを実証した。Vesting（権利確定）スケジュール（4年cliff+月次）、SAFEノート（Y Combinator開発）、優先株式（Liquidation Preference）設計が主要テーマ。","impact_summary":"エクイティ設計が創業チームの凝集性と長期インセンティブに与える根本的影響を実証し、起業家法務の実践知を整備した。","subfield":"entrepreneurship_venture","category":"A_foundations","school_of_thought":"コーポレートファイナンス論","era_start":2012,"schumpeter_layer":"ミクロ","innovation_type":"金融・法的イノベーション","cognitive_mechanism":"公平性認識と長期コミットメントの制度設計","key_researchers":["Noam Wasserman","Brad Feld","Jason Mendelson"],"key_works":["The Founders' Dilemmas (2012)","Venture Deals (2011)"],"keywords_ja":"スタートアップエクイティ,Vesting,SAFE,優先株,創業者のジレンマ","keywords_en":"startup equity,vesting,SAFE note,preferred stock,founder's dilemma"},
  {"id":"inno_ent_365","name_ja":"起業家精神の比較制度分析","name_en":"Comparative Institutional Analysis of Entrepreneurship","definition":"異なる資本主義の多様性（Varieties of Capitalism：HallとSoskice）が起業活動の形態・頻度に与える影響の比較研究。自由市場経済（LME：米国、英国）対調整市場経済（CME：ドイツ、日本）での起業家精神の違いが分析される。CMEでは急進的イノベーション起業より漸進的・技術深化型起業が相対的に優位となるメカニズムが研究される。","impact_summary":"資本主義の多様性と起業家精神の関係を体系化し、普遍的な起業支援政策への批判的視点を提供した。","subfield":"entrepreneurship_venture","category":"A_foundations","school_of_thought":"制度的起業家論","era_start":2001,"schumpeter_layer":"マクロ","innovation_type":"比較制度イノベーション","cognitive_mechanism":"制度的補完性と起業家行動の収束","key_researchers":["Peter Hall","David Soskice","Kathleen Thelen"],"key_works":["Varieties of Capitalism (2001)","Beyond Varieties of Capitalism (2010)"],"keywords_ja":"資本主義の多様性,VoC,LME,CME,比較起業家論","keywords_en":"varieties of capitalism,VoC,LME,CME,comparative entrepreneurship"},
  {"id":"inno_ent_366","name_ja":"クリエイターエコノミーの起業家精神","name_en":"Creator Economy Entrepreneurship","definition":"YouTuber、Podcaster、SubStack作家、TikTokerなどデジタルプラットフォームを活用してコンテンツ制作・収益化を行うクリエイターの起業家精神研究。SignalFireのレポートで5,000万人以上のクリエイターが1億ドル超の個人ビジネスを展開すると推計。Patron、Substack、Gumroad等のプラットフォームによる「1,000人のファン理論」（Kevin Kelly）の現代的実現が研究される。","impact_summary":"コンテンツ制作者を独立起業家として位置づけ、メディア産業と起業家精神の交差点を研究する新領域を確立した。","subfield":"entrepreneurship_venture","category":"B_systems","school_of_thought":"プラットフォーム論","era_start":2018,"schumpeter_layer":"ミクロ","innovation_type":"コンテンツ・プラットフォームイノベーション","cognitive_mechanism":"ファン関係資本と直接収益化の新モデル","key_researchers":["Kevin Kelly","Li Jin","SignalFire team"],"key_works":["1,000 True Fans (2008)","The Passion Economy (2019)"],"keywords_ja":"クリエイターエコノミー,1000人のファン,Substack,Patreon,コンテンツ起業","keywords_en":"creator economy,1000 true fans,Substack,Patreon,content entrepreneurship"},
  {"id":"inno_ent_367","name_ja":"フードテックスタートアップ","name_en":"FoodTech Startup Entrepreneurship","definition":"食品産業のイノベーションを担うフードテックスタートアップの研究。代替肉（Impossible Foods、Beyond Meat）、細胞培養肉、パーソナライズド栄養、フードデリバリー（UberEats、DoorDash）、農場管理AIが主要セグメント。FDA・農林水産省等の食品安全規制、消費者受容性（neophobia）、サプライチェーンの複雑さが起業課題。","impact_summary":"食料システムの持続可能性転換における起業家の役割を記述し、フードテックVC投資の基盤を整備した。","subfield":"entrepreneurship_venture","category":"B_systems","school_of_thought":"技術起業家論","era_start":2013,"schumpeter_layer":"ミクロ","innovation_type":"食料技術イノベーション","cognitive_mechanism":"食への保守性克服と代替食品市場創造","key_researchers":["Alon Chen","Pat Brown","AgFunder team"],"key_works":["Food Tech Revolution (2019)","Impossible Foods Case Study (2020)"],"keywords_ja":"フードテック,代替肉,細胞培養肉,フードデリバリー,Impossible Foods","keywords_en":"foodtech,alternative meat,cultured meat,food delivery,Impossible Foods"},
  {"id":"inno_ent_368","name_ja":"起業家精神と国際貿易政策","name_en":"Entrepreneurship and International Trade Policy","definition":"関税・輸出規制・自由貿易協定（FTA）等の貿易政策変化がスタートアップの国際化戦略に与える影響研究。Brexit後のスタートアップ活動変化、米中貿易戦争下での中国スタートアップのデカップリング、USMCA後のラテンアメリカVC投資変化が事例。WTOのTBT（Technical Barriers to Trade）がソフトウェアスタートアップの国際展開に与える制度的影響も研究される。","impact_summary":"貿易政策の変化が起業家精神の地理的機会空間を再編することを示し、政策変化に適応した国際化戦略研究を活性化した。","subfield":"entrepreneurship_venture","category":"B_systems","school_of_thought":"国際起業家論","era_start":2016,"schumpeter_layer":"マクロ","innovation_type":"国際貿易・政策イノベーション","cognitive_mechanism":"政策変化の起業機会と障壁への転換認識","key_researchers":["Justin Pierce","Peter Schott","Daron Acemoglu"],"key_works":["The Surprisingly Swift Decline of US Manufacturing (2016)","Trade Policy and Startup Performance (2019)"],"keywords_ja":"貿易政策,Brexit,米中貿易戦争,スタートアップ国際化,WTO","keywords_en":"trade policy,Brexit,US-China trade war,startup internationalization,WTO"},
  {"id":"inno_ent_369","name_ja":"ブロックチェーン起業家精神","name_en":"Blockchain Entrepreneurship","definition":"ブロックチェーン技術を基盤とするビジネス構築の起業家精神研究。Bitcoin、Ethereum基盤のDeFi（分散型金融）、NFTマーケットプレイス、DAO、Web3インフラ（IPFS、Chainlink）が対象。「コード・イズ・ロー」の原則と現実の規制環境の乖離、スマートコントラクトの脆弱性リスク、ブロックチェーンのスケーリング問題への起業家的対応が研究される。","impact_summary":"分散化技術の商業化における起業家的機会と制度的摩擦を記述し、Web3起業エコシステムの研究基盤を整備した。","subfield":"entrepreneurship_venture","category":"B_systems","school_of_thought":"フィンテック・Web3論","era_start":2015,"schumpeter_layer":"ミクロ","innovation_type":"分散技術イノベーション","cognitive_mechanism":"分散化信頼メカニズムの商業的活用","key_researchers":["Vitalik Buterin","Primavera De Filippi","Don Tapscott"],"key_works":["Ethereum White Paper (2014)","Blockchain Revolution (2016)"],"keywords_ja":"ブロックチェーン,DeFi,スマートコントラクト,DAO,Web3","keywords_en":"blockchain,DeFi,smart contracts,DAO,Web3"},
  {"id":"inno_ent_370","name_ja":"起業家精神と移民ポリシー","name_en":"Entrepreneurship and Immigration Policy","definition":"移民政策（ビザ規制、スタートアップビザ、高度人材移民プログラム）がスタートアップエコシステムに与える影響の実証研究。米国H-1Bビザ上限とシリコンバレースタートアップの関係（Bound et al. 2017）、カナダのスタートアップビザ制度の効果、英国のGlobal Talent Visaが起業家誘致に与えた影響が分析される。","impact_summary":"移民政策が起業エコシステムの人材供給を規定する主要変数であることを実証し、スタートアップビザ政策設計の証拠基盤を提供した。","subfield":"entrepreneurship_venture","category":"B_systems","school_of_thought":"移民起業家論","era_start":2010,"schumpeter_layer":"マクロ","innovation_type":"政策・人材イノベーション","cognitive_mechanism":"移民起業家の機会認識と制度的受容","key_researchers":["John Bound","Murat Demiral","William Kerr"],"key_works":["Skill Shortage and International Migration (2017)","America's New Immigrant Entrepreneurs (2007)"],"keywords_ja":"移民政策,スタートアップビザ,H-1B,高度人材,起業家誘致","keywords_en":"immigration policy,startup visa,H-1B,skilled talent,entrepreneurship attraction"},
  {"id":"inno_ent_371","name_ja":"プロダクトマーケットフィット（PMF）理論","name_en":"Product-Market Fit Theory","definition":"Marc Andreessenが2007年に提唱したPMF（製品市場適合）概念：「良い市場において、その市場を満足させる製品を持っていること」。Ben Horowitzの「the only thing that matters」発言が普及を後押し。PMFの定量的測定（Sean Ellis基準：40%以上が「非常に失望する」と回答する場合PMF達成）、コホート分析によるPMF診断、PMF前後の採用・成長戦略の違いが研究される。","impact_summary":"PMF概念がスタートアップの成長判断の中核指標となり、資金調達・採用・マーケティング投資のタイミング基準を整備した。","subfield":"entrepreneurship_venture","category":"A_foundations","school_of_thought":"実践的起業家方法論","era_start":2007,"schumpeter_layer":"ミクロ","innovation_type":"製品戦略イノベーション","cognitive_mechanism":"顧客価値実感の閾値と成長加速の関係","key_researchers":["Marc Andreessen","Sean Ellis","Andy Rachleff"],"key_works":["The Only Thing That Matters (2007)","Hacking Growth (2017)"],"keywords_ja":"PMF,製品市場適合,Sean Ellis,コホート分析,スケーリング判断","keywords_en":"PMF,product-market fit,Sean Ellis,cohort analysis,scaling decision"},
  {"id":"inno_ent_372","name_ja":"起業家的自己効力感","name_en":"Entrepreneurial Self-Efficacy","definition":"Bandura（1977）の自己効力感理論を起業家研究に応用したChen et al.（1998）のEntrepreneurial Self-Efficacy（ESE）概念。起業関連タスク（マーケティング、財務管理、製品開発等）を遂行できるという個人の信念がESE。ESEが起業意図→起業行動→新規事業パフォーマンスに正の影響を持つことが多数の実証研究で確認されている。起業家教育によるESE向上効果も測定されている。","impact_summary":"起業意図と行動の橋渡し変数としてESEを確立し、800件以上の実証研究の基盤となるとともに起業家教育設計に貢献した。","subfield":"entrepreneurship_venture","category":"A_foundations","school_of_thought":"認知的起業家論","era_start":1998,"schumpeter_layer":"ミクロ","innovation_type":"心理・認知イノベーション","cognitive_mechanism":"起業タスク能力への信念と行動意図の直接効果","key_researchers":["Chin-Chang Chen","Patricia Greene","Lowell Busenitz"],"key_works":["Does Entrepreneurial Self-Efficacy Distinguish Entrepreneurs? (1998)","Entrepreneurial Self-Efficacy and Intentions (2001)"],"keywords_ja":"起業家的自己効力感,ESE,起業意図,Bandura,能力信念","keywords_en":"entrepreneurial self-efficacy,ESE,entrepreneurial intention,Bandura,capability belief"},
  {"id":"inno_ent_373","name_ja":"起業家的意図モデル","name_en":"Entrepreneurial Intention Models","definition":"起業を意図するかどうかを予測する心理的モデルの研究。Ajzenの計画行動理論（TPB）と Shaperoの起業出来事モデルを統合したBird（1988）の意図モデルが基盤。Linanら（2011）のEIQ（Entrepreneurial Intention Questionnaire）が標準測定尺度。態度・主観的規範・知覚行動制御の3要素と起業意図の関係が50カ国以上で実証されている。","impact_summary":"起業意図の心理的先行要因を定量化し、介入可能な起業教育変数の特定に貢献した。","subfield":"entrepreneurship_venture","category":"A_foundations","school_of_thought":"認知的起業家論","era_start":1988,"schumpeter_layer":"ミクロ","innovation_type":"心理・計量イノベーション","cognitive_mechanism":"態度形成から行動意図への三段階プロセス","key_researchers":["Icek Ajzen","Francisco Linan","Alain Fayolle"],"key_works":["The Theory of Planned Behavior (1991)","Entrepreneurial Intentions (2011)"],"keywords_ja":"起業家的意図,計画行動理論,EIQ,態度,主観的規範","keywords_en":"entrepreneurial intention,theory of planned behavior,EIQ,attitude,subjective norm"},
  {"id":"inni_ent_374","name_ja":"起業家精神とモラルハザード","name_en":"Moral Hazard in Entrepreneurship","definition":"VC投資家と起業家の間の情報非対称性・インセンティブ乖離（モラルハザード）の研究。投資後の起業家の努力水準低下、VC側の過度なリスク要求、創業者のprivate benefit（名声・コントロール欲求）が財務的価値最大化と相反する問題が分析される。Staged financingとMilestone monitoring、Board composition設計がモラルハザード緩和メカニズムとして研究される。","impact_summary":"VC-起業家間のエージェンシー問題を体系化し、投資契約設計・ボード構成・マイルストーン設定の理論基盤を提供した。","subfield":"entrepreneurship_venture","category":"A_foundations","school_of_thought":"VC論","era_start":1994,"schumpeter_layer":"ミクロ","innovation_type":"ガバナンス・契約イノベーション","cognitive_mechanism":"段階投資と監視による努力水準維持","key_researchers":["William Sahlman","Paul Gompers","Josh Lerner"],"key_works":["The Structure and Governance of Venture Capital (1990)","The Agency Cost of Venture Capital (1995)"],"keywords_ja":"モラルハザード,エージェンシー問題,段階投資,Board,VC契約","keywords_en":"moral hazard,agency problem,staged financing,board,VC contract"},
  {"id":"inno_ent_375","name_ja":"起業家精神とリバースイノベーション","name_en":"Reverse Innovation and Entrepreneurship","definition":"新興国市場向けに開発された低コスト・低機能製品が先進国市場に逆輸出される「リバースイノベーション」（Immelt et al. 2009）の起業家精神研究。GEヘルスケアの携帯型心電計（インド向け→米国市場）、Jaipur Foot義足、India栄養製品の逆輸入が事例。「ジュガード（Jugaad）イノベーション」とも接続し、制約下イノベーションの新興国起業家精神を研究する。","impact_summary":"イノベーションの地理的方向性を逆転させる起業家精神を理論化し、南から北への技術移転モデルを提示した。","subfield":"entrepreneurship_venture","category":"A_foundations","school_of_thought":"新興市場起業家論","era_start":2009,"schumpeter_layer":"メゾ","innovation_type":"リバース・制約イノベーション","cognitive_mechanism":"制約が創造性を生む逆説的設計思考","key_researchers":["Jeffrey Immelt","Vijay Govindarajan","Chris Trimble"],"key_works":["How GE is Disrupting Itself (2009)","Jugaad Innovation (2012)"],"keywords_ja":"リバースイノベーション,ジュガード,新興国,制約下イノベーション","keywords_en":"reverse innovation,jugaad,emerging markets,constraint-driven innovation"},
  {"id":"inno_ent_376","name_ja":"起業家精神のテキスト分析","name_en":"Text Analysis in Entrepreneurship Research","definition":"自然言語処理（NLP）・機械学習によるピッチデッキ、VC投資家レター、起業家ナラティブ、会社説明文のテキスト分析を起業家研究に応用する方法論的研究。感情分析による創業者の楽観性測定、トピックモデリングによる起業家機会の時系列分析、CrunchbaseテキストのAI解析が実施されている。大規模テキストデータを活用した起業家研究の新地平を開いた。","impact_summary":"計算社会科学の手法を起業家研究に持ち込み、従来不可能だった大規模実証分析の可能性を切り開いた。","subfield":"entrepreneurship_venture","category":"A_foundations","school_of_thought":"実証的起業家研究","era_start":2016,"schumpeter_layer":"ミクロ","innovation_type":"研究方法論イノベーション","cognitive_mechanism":"言語的信号と企業成果の統計的関係","key_researchers":["Alireza Doroudi","James Bort","Pinar Yildirim"],"key_works":["Text as Data in Entrepreneurship Research (2020)","Startup Discourse Analysis (2021)"],"keywords_ja":"テキスト分析,NLP,ピッチデッキ,感情分析,計算起業家研究","keywords_en":"text analysis,NLP,pitch deck,sentiment analysis,computational entrepreneurship"},
  {"id":"inno_ent_377","name_ja":"起業家精神の制度的逸脱論","name_en":"Institutional Deviance in Entrepreneurship","definition":"既存制度・規制の外部または境界で活動する起業家（institutional entrepreneurs）が新しい制度を創造するプロセスの研究。Airbnbによるホテル規制への挑戦、Uberのタクシー規制回避、大麻スタートアップの違法状態からの合法化プロセスが事例。DiMaggio & Powell（1983）の制度的同型化への抵抗としての起業家的逸脱が分析される。","impact_summary":"制度の創造・変革における起業家の役割を理論化し、規制イノベーションと政策変更の起業家的ドライバーを研究する枠組みを提供した。","subfield":"entrepreneurship_venture","category":"A_foundations","school_of_thought":"制度的起業家論","era_start":1988,"schumpeter_layer":"メゾ","innovation_type":"制度・規制イノベーション","cognitive_mechanism":"制度的空隙の認識と変革への行動コミットメント","key_researchers":["Paul DiMaggio","Walter Powell","Thomas Lawrence"],"key_works":["The Iron Cage Revisited (1983)","Institutional Entrepreneurship (2002)"],"keywords_ja":"制度的起業家,規制逸脱,Airbnb,Uber,制度変革","keywords_en":"institutional entrepreneur,regulatory deviance,Airbnb,Uber,institutional change"},
  {"id":"inno_ent_378","name_ja":"企業家精神とAIテックバブル","name_en":"Entrepreneurship in the AI Tech Bubble","definition":"ChatGPT登場（2022年末）以降の生成AIスタートアップ投資急増とその持続可能性の研究。2023年AI投資は前年比3倍超に達し、「AI first」スタートアップの差別化困難性（LLMのコモディティ化）、モデルラッパービジネスの脆弱性、計算コストとマージンの矛盾が研究される。Anthropic、OpenAI等のAIモデル会社とアプリケーション層スタートアップの役割分担も分析対象。","impact_summary":"AI技術サイクルにおける起業機会と競争構造を記述し、AIスタートアップ投資の評価フレームを提供した。","subfield":"entrepreneurship_venture","category":"B_systems","school_of_thought":"技術起業家論","era_start":2023,"schumpeter_layer":"ミクロ","innovation_type":"AI・生成AIイノベーション","cognitive_mechanism":"技術ハイプサイクルと起業機会の認識バイアス","key_researchers":["Sam Altman","Dario Amodei","Elad Gil"],"key_works":["High Growth Handbook (2018)","AI Market Report (2023)"],"keywords_ja":"AI起業家精神,生成AI,LLM,AIスタートアップ,コモディティ化","keywords_en":"AI entrepreneurship,generative AI,LLM,AI startup,commoditization"},
  {"id":"inno_ent_379","name_ja":"起業家精神と知識集約型産業","name_en":"Knowledge-Intensive Industry Entrepreneurship","definition":"コンサルティング、ソフトウェア、会計、法律、R&D等の知識集約型産業における起業家精神の研究。Strambach（2008）によれば知識集約型ビジネスサービス（KIBS）は産業全体のイノベーション媒介者として機能する。知識資産の保護（非競業条項）、クライアント依存リスク、知識のコモディティ化・自動化（AI弁護士等）が固有課題。","impact_summary":"知識・サービス産業の起業家論を確立し、専門職サービスのイノベーション研究の体系化に貢献した。","subfield":"entrepreneurship_venture","category":"A_foundations","school_of_thought":"知識ベース論","era_start":2008,"schumpeter_layer":"ミクロ","innovation_type":"知識サービスイノベーション","cognitive_mechanism":"知識の組み合わせと専門的判断力の商業化","key_researchers":["Simone Strambach","Ian Miles","Jeremy Howells"],"key_works":["Knowledge-Intensive Business Services (2008)","Innovation Systems (2000)"],"keywords_ja":"知識集約型産業,KIBS,専門職起業,知識コモディティ化","keywords_en":"knowledge-intensive industry,KIBS,professional service entrepreneurship,knowledge commoditization"},
  {"id":"inno_ent_380","name_ja":"アントレプレナーシップと機械学習応用","name_en":"Machine Learning Applications in Entrepreneurship Research","definition":"機械学習・AIを起業家研究のツールとして活用する方法論的研究。スタートアップ成功予測モデル（ランダムフォレスト、XGBoost）、VC投資意思決定のAI補助、特許テキストからのイノベーション測定、ネットワーク分析による起業家コネクター特定が研究される。CB Insights、Crunchbase、PitchBookのビッグデータ活用が研究の基盤インフラ。","impact_summary":"データ科学と起業家研究の統合により、大規模・リアルタイム実証分析が可能になり、起業家研究の精度と応用範囲を拡大した。","subfield":"entrepreneurship_venture","category":"A_foundations","school_of_thought":"実証的起業家研究","era_start":2018,"schumpeter_layer":"ミクロ","innovation_type":"研究方法論イノベーション","cognitive_mechanism":"データパターン認識と予測モデル構築","key_researchers":["Olav Sorenson","Sampsa Samila","Tian Zheng"],"key_works":["Social Networks and Entrepreneurship (2017)","Predicting Startup Success with ML (2019)"],"keywords_ja":"機械学習,スタートアップ予測,CB Insights,Crunchbase,ビッグデータ","keywords_en":"machine learning,startup prediction,CB Insights,Crunchbase,big data"},
  {"id":"inno_ent_381","name_ja":"Quadruple Helixと起業家精神","name_en":"Quadruple Helix and Entrepreneurship","definition":"Triple Helix（大学-産業-政府）にCivil Society（市民社会・ユーザー）を加えたQuadruple Helixモデルの起業家精神への応用。Carayannis & Campbell（2009）が提唱。ユーザーイノベーション（Von Hippel）との接続で、市民起業家・コミュニティ起業・ソーシャルイノベーションが研究対象として浮上する。公共問題解決のためのマルチアクター協働起業が主要テーマ。","impact_summary":"市民・ユーザーを起業エコシステムの主体として組み込むQuadruple Helixモデルを確立し、共創型イノベーション政策の理論基盤を提供した。","subfield":"entrepreneurship_venture","category":"B_systems","school_of_thought":"エコシステム論","era_start":2009,"schumpeter_layer":"メゾ","innovation_type":"社会システムイノベーション","cognitive_mechanism":"市民参加と知識民主化による起業機会創出","key_researchers":["Elias Carayannis","David Campbell","Erik von Hippel"],"key_works":["Mode 3 Knowledge Production (2009)","Democratizing Innovation (2005)"],"keywords_ja":"Quadruple Helix,市民社会,ユーザーイノベーション,コミュニティ起業","keywords_en":"quadruple helix,civil society,user innovation,community entrepreneurship"},
  {"id":"inno_ent_382","name_ja":"起業家精神の正当性理論","name_en":"Legitimacy Theory in Entrepreneurship","definition":"新規ベンチャーが外部ステークホルダーから正当性（legitimacy）を獲得するプロセスの研究。Aldrich & Fiol（1994）は認知的正当性（知識・理解）と社会政治的正当性（価値・規範への適合）の2次元を提示した。顧客・投資家・メディア・規制機関それぞれへの正当性構築戦略（模倣、認証取得、著名人起用等）が研究される。","impact_summary":"新規市場に参入する起業家が直面する「正当性ギャップ」を理論化し、起業初期の外部関係管理戦略の研究基盤を整備した。","subfield":"entrepreneurship_venture","category":"A_foundations","school_of_thought":"制度的起業家論","era_start":1994,"schumpeter_layer":"ミクロ","innovation_type":"組織・制度イノベーション","cognitive_mechanism":"正当性の社会的構築と外部承認の獲得","key_researchers":["Howard Aldrich","Marlene Fiol","Mark Suchman"],"key_works":["Fools Rush In? (1994)","Managing Legitimacy (1995)"],"keywords_ja":"正当性,起業家,ステークホルダー,認知的正当性,新規参入","keywords_en":"legitimacy,entrepreneurship,stakeholders,cognitive legitimacy,new venture"},
  {"id":"inno_ent_383","name_ja":"スタートアップのプロダクトデザイン","name_en":"Product Design in Startups","definition":"スタートアップのUI/UX・インタラクションデザイン・ブランドデザインのプロセスと競争優位への影響研究。デザイン思考（IDEO、dschool）がスタートアップの人間中心設計に普及した経緯、Figmaがコラボレーション設計ツールとしてデファクト化した背景、Apple・Airbnbのデザイン起業家（design founder）事例が研究される。","impact_summary":"デザインをスタートアップの差別化要因として位置づけ、「デザイン主導スタートアップ」という概念を確立した。","subfield":"entrepreneurship_venture","category":"A_foundations","school_of_thought":"スタートアップ成長論","era_start":2009,"schumpeter_layer":"ミクロ","innovation_type":"デザインイノベーション","cognitive_mechanism":"ユーザー共感と審美性の製品価値への変換","key_researchers":["Tom Kelley","Tim Brown","John Maeda"],"key_works":["Change by Design (2009)","Design in Tech Report (annual)"],"keywords_ja":"プロダクトデザイン,UI/UX,デザイン思考,Figma,デザイン起業家","keywords_en":"product design,UI/UX,design thinking,Figma,design founder"},
  {"id":"inno_ent_384","name_ja":"アフリカ農業起業家精神","name_en":"African Agricultural Entrepreneurship","definition":"サハラ以南アフリカの農業起業家精神研究。農地所有権不安定、気候変動脆弱性、農業金融アクセス困難という構造的課題の中で、モバイルアグリ情報サービス（M-Farm、AgroCenta）、農業EC（Twiga Foods）、スマート灌漑スタートアップが台頭する現象を分析する。青年農業起業家の土地アクセス問題と代替農業モデル（インドア農業、コントラクトファーミング）も研究される。","impact_summary":"アフリカ農業の技術革新を起業家精神の観点から分析し、食料安全保障と農業起業支援政策の理論基盤を提供した。","subfield":"entrepreneurship_venture","category":"B_systems","school_of_thought":"新興市場起業家論","era_start":2015,"schumpeter_layer":"ミクロ","innovation_type":"農業・食料イノベーション","cognitive_mechanism":"農業現場のデジタル化機会認識","key_researchers":["Sanne Vreeke","Bas Rüter","David Mwangi"],"key_works":["Digital Agriculture in Africa (2019)","Agri-Entrepreneurship in Sub-Saharan Africa (2020)"],"keywords_ja":"アフリカ農業,Twiga Foods,M-Farm,農業EC,青年農業起業家","keywords_en":"Africa agriculture,Twiga Foods,M-Farm,agri-e-commerce,youth agripreneurs"},
  {"id":"inno_ent_385","name_ja":"スタートアップの価格戦略","name_en":"Startup Pricing Strategy","definition":"新規事業の製品・サービス価格設定の戦略的研究。コスト加算型（cost-plus）から顧客価値ベース（value-based pricing）への移行、SaaSのTier/Seat/UsageベースPricingモデル、フリーミアムの転換率最適化が研究される。Madhavan Ramanujam（Monetizing Innovation）の価格先行設計（pricing before product design）アプローチが注目された。","impact_summary":"スタートアップの収益最大化において価格設計が製品設計と同等以上に重要であることを示し、起業家の価格論的意識向上に貢献した。","subfield":"entrepreneurship_venture","category":"A_foundations","school_of_thought":"スタートアップ成長論","era_start":2016,"schumpeter_layer":"ミクロ","innovation_type":"価格・収益イノベーション","cognitive_mechanism":"支払意思額の顧客セグメント別推定と価格設計","key_researchers":["Madhavan Ramanujam","Georg Tacke","Patrick Campbell"],"key_works":["Monetizing Innovation (2016)","The Price Intelligently Reports (annual)"],"keywords_ja":"価格戦略,SaaS Pricing,フリーミアム転換,価値ベース価格","keywords_en":"pricing strategy,SaaS pricing,freemium conversion,value-based pricing"},
  {"id":"inno_ent_386","name_ja":"起業家精神と国家資本主義","name_en":"Entrepreneurship and State Capitalism","definition":"国家が市場の主要プレイヤーとして積極的に関与する「国家資本主義」（中国、サウジアラビア、UAE等）における起業家精神の研究。SOE（国有企業）との競争、政府の起業家育成政策（中国の大衆創業・万衆創新）、国家VC（Saudi Aramco Ventures、Mubadala）が民間起業家に与える影響が分析される。","impact_summary":"国家主導の起業家エコシステムの可能性と限界を分析し、西洋モデルを超えた多様な起業家精神の類型論を提示した。","subfield":"entrepreneurship_venture","category":"B_systems","school_of_thought":"比較起業家論","era_start":2012,"schumpeter_layer":"マクロ","innovation_type":"国家主導起業イノベーション","cognitive_mechanism":"国家的インセンティブと民間起業家精神の相互作用","key_researchers":["Ian Bremmer","Arthur Kroeber","Carl Walter"],"key_works":["The End of the Free Market (2010)","China's Economy (2016)"],"keywords_ja":"国家資本主義,中国起業家精神,大衆創業,SOE,国家VC","keywords_en":"state capitalism,Chinese entrepreneurship,mass entrepreneurship,SOE,sovereign VC"},
  {"id":"inno_ent_387","name_ja":"起業家精神の認知負荷研究","name_en":"Cognitive Load in Entrepreneurship","definition":"起業家が直面する情報過負荷・多重タスク・意思決定疲労が判断品質に与える影響の研究。心理学的「決定疲労（decision fatigue）」がVC/起業家の午後の判断品質を低下させることを示した実験研究、「単純な意思決定ルール（ヒューリスティクス）」の適応的有効性（Gigerenzer）が研究される。起業初期の意思決定アーキテクチャ設計（何に集中するか）が重要課題として浮上している。","impact_summary":"情報過負荷下での起業家意思決定の認知的制約を明示化し、意思決定プロセス設計と優先順位付け手法の研究を促した。","subfield":"entrepreneurship_venture","category":"A_foundations","school_of_thought":"認知的起業家論","era_start":2011,"schumpeter_layer":"ミクロ","innovation_type":"認知・行動イノベーション","cognitive_mechanism":"認知負荷管理と適応的ヒューリスティクス","key_researchers":["Gerd Gigerenzer","Daniel Kahneman","Shai Danziger"],"key_works":["Rationality for Mortals (2008)","Extraneous Factors in Judicial Decisions (2011)"],"keywords_ja":"認知負荷,決定疲労,ヒューリスティクス,情報過負荷,起業家意思決定","keywords_en":"cognitive load,decision fatigue,heuristics,information overload,entrepreneurial decision-making"},
  {"id":"inno_ent_388","name_ja":"起業家精神とオープンイノベーション2.0","name_en":"Open Innovation 2.0 and Entrepreneurship","definition":"Chesbrough（2003）のオープンイノベーションをQuadruple Helix・デジタルプラットフォーム・社会的価値創造に拡張した「Open Innovation 2.0」（Curley & Salmelin 2013）の起業家精神への応用。欧州委員会が推進するOI2モデルでは政府・産業・学術・市民の協働によるexponential growthを目指す。共同創造（co-creation）と価値共有（value sharing）が新起業モデルの中核となる。","impact_summary":"オープンイノベーション概念を社会的価値創造と市民参加に拡張し、公共部門での起業家的イノベーション論を確立した。","subfield":"entrepreneurship_venture","category":"B_systems","school_of_thought":"オープンイノベーション論","era_start":2013,"schumpeter_layer":"メゾ","innovation_type":"協働イノベーション","cognitive_mechanism":"多主体間の知識共有と価値共創","key_researchers":["Martin Curley","Bror Salmelin","Henry Chesbrough"],"key_works":["Open Innovation 2.0: The New Mode of Digital Innovation (2013)","Open Services Innovation (2011)"],"keywords_ja":"オープンイノベーション2.0,OI2,共同創造,Quadruple Helix,欧州委員会","keywords_en":"Open Innovation 2.0,OI2,co-creation,quadruple helix,European Commission"},
  {"id":"inno_ent_389","name_ja":"スタートアップの品質管理と認証","name_en":"Quality Management and Certification in Startups","definition":"スタートアップが特定市場（医療機器、航空、金融、食品等）への参入に必要な規制認証・品質管理システム（ISO 13485、FDA 510k、CE marking）取得プロセスと経営への影響の研究。認証取得コスト・時間が競合に対する「モートの役割」を果たす側面と、スタートアップの動きを遅らせる障壁になる側面の両面が分析される。","impact_summary":"規制認証を戦略的参入障壁として位置づけ、規制環境依存型産業での起業戦略論を整備した。","subfield":"entrepreneurship_venture","category":"A_foundations","school_of_thought":"技術起業家論","era_start":2010,"schumpeter_layer":"ミクロ","innovation_type":"規制・品質イノベーション","cognitive_mechanism":"規制要件の戦略的活用と参入障壁化","key_researchers":["Anne Mette Søberg","Timothy Simcoe","Sharon Novak"],"key_works":["Standards and Innovation (2019)","Quality Management in Healthcare Startups (2020)"],"keywords_ja":"品質管理,ISO,FDA認証,CE marking,規制参入障壁","keywords_en":"quality management,ISO,FDA certification,CE marking,regulatory moat"},
  {"id":"inno_ent_390","name_ja":"スタートアップのオペレーション最適化","name_en":"Operations Optimization in Startups","definition":"スタートアップが成長段階で直面するオペレーション課題（顧客対応自動化、物流最適化、品質管理、コスト管理）の研究。Lean製造（Toyota Production System）のスタートアップ適用、OKR（目標管理）・KPI体系設計、週次運営ルーティンの標準化が研究される。「Scale-up」フェーズの最大瓶頸はオペレーション能力不足であるという実証が蓄積されている。","impact_summary":"スタートアップのスケールアップを阻むオペレーション制約を特定し、成長段階での組織能力構築の実践知を整備した。","subfield":"entrepreneurship_venture","category":"A_foundations","school_of_thought":"組織論的起業家論","era_start":2014,"schumpeter_layer":"ミクロ","innovation_type":"オペレーション・プロセスイノベーション","cognitive_mechanism":"プロセス標準化と組織学習の正のフィードバック","key_researchers":["Alex Osterwalder","Patrick Lencioni","Andy Grove"],"key_works":["Value Proposition Design (2014)","Measure What Matters (2018)"],"keywords_ja":"オペレーション最適化,OKR,Lean,スケールアップ,KPI","keywords_en":"operations optimization,OKR,lean,scale-up,KPI"},
  {"id":"inno_ent_391","name_ja":"起業家精神と民族的ネットワーク","name_en":"Ethnic Networks and Entrepreneurship","definition":"共通の民族的背景を持つ起業家ネットワーク（エスニック・アンクレーブ、ディアスポラ起業家）の機能と経済的影響の研究。Portes & Sensenbrenner（1993）の社会関係資本（bonding vs bridging）の民族的文脈への適用、シリコンバレーにおける中国系・インド系ネットワーク（US-China、TiE等）の役割が分析される。","impact_summary":"民族的ネットワークが起業機会・資金・市場アクセスに与える具体的効果を実証し、多文化起業家精神研究の基盤を整備した。","subfield":"entrepreneurship_venture","category":"A_foundations","school_of_thought":"移民起業家論","era_start":1993,"schumpeter_layer":"ミクロ","innovation_type":"ネットワーク・文化イノベーション","cognitive_mechanism":"民族的信頼と集団的資源動員","key_researchers":["Alejandro Portes","Julia Sensenbrenner","Ivan Light"],"key_works":["Embeddedness and Immigration (1993)","Ethnic Economy (2000)"],"keywords_ja":"エスニックネットワーク,移民起業家,ディアスポラ,TiE,民族資本","keywords_en":"ethnic network,immigrant entrepreneurship,diaspora,TiE,ethnic capital"},
  {"id":"inno_ent_392","name_ja":"起業家精神とスポーツビジネス","name_en":"Sports Business Entrepreneurship","definition":"スポーツ産業における起業家精神の研究。スポーツテック（wearable分析、eスポーツ）、スポーツメディア（DAZN等）、アスリート起業家（NBA/NFL/Neymar等の選手によるVC参入）、eスポーツチーム経営が研究対象。スポーツエコシステムの構造（リーグ・クラブ・メディア・スポンサー・ファン）とスタートアップの参入機会が分析される。","impact_summary":"スポーツ産業の起業家的側面を学術化し、スポーツテック・eスポーツの投資評価論を整備した。","subfield":"entrepreneurship_venture","category":"B_systems","school_of_thought":"産業起業家論","era_start":2015,"schumpeter_layer":"ミクロ","innovation_type":"スポーツ・エンタメイノベーション","cognitive_mechanism":"ファン感情と商業化の接点設計","key_researchers":["David Muret","Pamela Wicker","Tim Pawlowski"],"key_works":["Sports Business Handbook (2019)","eSpors and Entrepreneurship (2021)"],"keywords_ja":"スポーツビジネス,eスポーツ,スポーツテック,アスリート起業家","keywords_en":"sports business,esports,sportstech,athlete entrepreneur"},
  {"id":"inno_ent_393","name_ja":"起業家精神とバリューチェーン統合","name_en":"Value Chain Integration in Startups","definition":"スタートアップが供給者・中間流通・小売等のバリューチェーンを統合・ディスラプトする戦略の研究。DTC（Direct to Consumer：直接消費者販売）モデル（Warby Parker、Casper、Allbirds）がバリューチェーン分解事例として研究される。バリューチェーン全体の垂直統合コスト対柔軟性のトレードオフ、プラットフォームによるバリューチェーン再編が主要テーマ。","impact_summary":"DTCモデルとプラットフォームによるバリューチェーン再編を理論化し、消費者向けスタートアップの競争戦略研究に貢献した。","subfield":"entrepreneurship_venture","category":"A_foundations","school_of_thought":"産業組織論的起業家論","era_start":2010,"schumpeter_layer":"ミクロ","innovation_type":"バリューチェーンイノベーション","cognitive_mechanism":"中間マージンの排除と消費者直結の価値提案","key_researchers":["Jason Del Rey","Sucharita Kodali","Scott Galloway"],"key_works":["The Four (2017)","Direct-to-Consumer Commerce (2018)"],"keywords_ja":"DTC,バリューチェーン,Warby Parker,垂直統合,中間排除","keywords_en":"DTC,value chain,Warby Parker,vertical integration,disintermediation"},
  {"id":"inno_ent_394","name_ja":"起業家精神とナノテクノロジー","name_en":"Nanotechnology Entrepreneurship","definition":"ナノテクノロジー（1〜100nmスケールの物質操作）を基盤とするスタートアップの起業家精神研究。ナノ材料（カーボンナノチューブ、グラフェン）、ナノメディスン（薬物送達システム）、ナノ電子デバイスが対象。NCI（米国ナノテクノロジー推進機構）等の政府支援プログラムとの連携、長い研究→商業化サイクル、安全規制の不確実性が固有課題。","impact_summary":"ナノテクノロジーの商業化における起業家的役割を記述し、ディープサイエンス起業の一類型としての研究基盤を整備した。","subfield":"entrepreneurship_venture","category":"B_systems","school_of_thought":"技術起業家論","era_start":2005,"schumpeter_layer":"ミクロ","innovation_type":"ナノ技術イノベーション","cognitive_mechanism":"極小スケールの技術制御と商業的応用の発想","key_researchers":["Mihail Roco","Mark Modzelewski","David Berube"],"key_works":["Nanotechnology: Societal Implications (2006)","Nanotech Startup Ecosystem (2010)"],"keywords_ja":"ナノテクノロジー,ナノ材料,ナノメディスン,ディープサイエンス","keywords_en":"nanotechnology,nanomaterials,nanomedicine,deep science startup"},
  {"id":"inno_ent_395","name_ja":"起業家精神の心理的オーナーシップ","name_en":"Psychological Ownership in Entrepreneurship","definition":"組織・製品・プロジェクトに対して「これは自分のものだ」という感覚（心理的オーナーシップ）が従業員の起業行動・イントラプレナーシップに与える影響の研究。Pierce et al.（2003）の心理的オーナーシップ理論の起業家への応用。ESOPや株式報酬による心理的オーナーシップ強化と業績の関係、创業者の感情的オーナーシップがスケールアップ時の障壁となる逆説も研究される。","impact_summary":"心理的所有感が起業家的行動を駆動するメカニズムを明示化し、組織内起業（イントラプレナーシップ）設計に応用された。","subfield":"entrepreneurship_venture","category":"A_foundations","school_of_thought":"行動的起業家論","era_start":2003,"schumpeter_layer":"ミクロ","innovation_type":"心理・組織イノベーション","cognitive_mechanism":"所有感と責任感の内発的動機への変換","key_researchers":["Jon Pierce","Iiro Jussila","Kenneth Kostova"],"key_works":["Psychological Ownership Theory (2003)","Ownership at Work (2004)"],"keywords_ja":"心理的オーナーシップ,ESOP,イントラプレナーシップ,所有感,責任感","keywords_en":"psychological ownership,ESOP,intrapreneurship,sense of ownership,responsibility"},
  {"id":"inno_ent_396","name_ja":"スタートアップの国際R&D戦略","name_en":"International R&D Strategy in Startups","definition":"グローバルに展開するスタートアップが複数国にR&D拠点を設置する戦略と管理の研究。Eastern Europe（ウクライナ、ポーランド）、インド、中国のエンジニアリングハブ活用、分散型チームでの製品開発管理（GitHub Actions、Linear等のツール）、タイムゾーン分散の生産性への影響が研究される。COVID後のリモートファーストスタートアップの国際R&D戦略が急速に研究が進んでいる。","impact_summary":"スタートアップの国際R&D分散化を理論化し、地理的多様性と組織統合の均衡管理の知見を提供した。","subfield":"entrepreneurship_venture","category":"A_foundations","school_of_thought":"国際起業家論","era_start":2015,"schumpeter_layer":"ミクロ","innovation_type":"国際R&D組織イノベーション","cognitive_mechanism":"地理的分散と製品一貫性のバランス","key_researchers":["Annapoornima Subramanian","Suma Athreye","Stefanie Lenway"],"key_works":["Offshoring Innovation (2018)","Global R&D Management (2020)"],"keywords_ja":"国際R&D,分散開発,リモートチーム,エンジニアリングハブ","keywords_en":"international R&D,distributed development,remote team,engineering hub"},
  {"id":"inno_ent_397","name_ja":"起業家精神とエネルギー移行","name_en":"Entrepreneurship and Energy Transition","definition":"化石燃料から再生可能エネルギーへの移行（エネルギー移行）における起業家精神の役割研究。太陽光パネル設置スタートアップ（SolarCity等）、エネルギー管理ソフトウェア（Arcadia）、電力P2Pマーケットプレイス、水素スタートアップ（Nel ASA）が研究対象。エネルギー価格規制・電力グリッド規制・炭素税政策が起業機会と障壁の両面を生む制度的文脈が分析される。","impact_summary":"エネルギー移行を起業家精神研究の主要テーマとして確立し、クリーンエネルギー起業の政策・投資環境研究を活性化した。","subfield":"entrepreneurship_venture","category":"B_systems","school_of_thought":"持続可能性起業家論","era_start":2010,"schumpeter_layer":"メゾ","innovation_type":"エネルギー移行イノベーション","cognitive_mechanism":"規制機会の認識とカーボン価格の事業可能性","key_researchers":["Joern Hoppmann","Karoline Rogge","Frank Geels"],"key_works":["Entrepreneurship in Energy Transition (2017)","Electricity Market Reform (2020)"],"keywords_ja":"エネルギー移行,再生可能エネルギー,SolarCity,水素,カーボン税","keywords_en":"energy transition,renewable energy,SolarCity,hydrogen,carbon tax"},
  {"id":"inno_ent_398","name_ja":"スタートアップのコミュニティビルディング","name_en":"Community Building in Startups","definition":"製品・サービスを核とするコミュニティ形成戦略と、それが成長・リテンション・防衛力に与える影響の研究。Discord（ゲーマーコミュニティ）、Notion（ユーザーアンバサダー）、HubSpot（Inbound Marketing Community）が代表事例。CMX（Community Manager Exchange）フレームワーク、コミュニティ主導成長（Community-Led Growth）の定量化が研究される。","impact_summary":"コミュニティを競争優位の源泉として位置づけ、製品中心から人間関係中心の成長戦略論を確立した。","subfield":"entrepreneurship_venture","category":"A_foundations","school_of_thought":"スタートアップ成長論","era_start":2015,"schumpeter_layer":"ミクロ","innovation_type":"コミュニティ・関係性イノベーション","cognitive_mechanism":"帰属意識とコミュニティアイデンティティの形成","key_researchers":["David Spinks","Fabian Geyrhalter","Carrie Melissa Jones"],"key_works":["The Business of Belonging (2021)","Building Brand Communities (2018)"],"keywords_ja":"コミュニティビルディング,Discord,CLG,ブランドコミュニティ,アンバサダー","keywords_en":"community building,Discord,CLG,brand community,ambassador"},
  {"id":"inno_ent_399","name_ja":"起業家精神の神経多様性と起業アドバンテージ","name_en":"Neurodiversity as Entrepreneurial Advantage","definition":"ADHD・自閉症スペクトラム（ASD）・ディスレクシア等の神経多様性（neurodiversity）が起業家精神に与えるアドバンテージの研究。Wiklund et al.（2018）は起業家集団にADHD傾向が有意に高いことを示した。ハイパーフォーカス・パターン認識・リスク耐性・非線形思考等の神経多様性特性が起業的機会認識と問題解決に有利に働くメカニズムが研究される。","impact_summary":"神経多様性を障害ではなく起業的アドバンテージとして再フレーミングし、神経多様性起業家支援プログラムの設計に貢献した。","subfield":"entrepreneurship_venture","category":"A_foundations","school_of_thought":"進化心理学的起業家論","era_start":2018,"schumpeter_layer":"ミクロ","innovation_type":"認知・心理的イノベーション","cognitive_mechanism":"非定型認知パターンによる機会認識の独自性","key_researchers":["Johan Wiklund","Siri Terjesen","Karl Wennberg"],"key_works":["Examining ADHD and Entrepreneurial Action (2018)","Neurodiversity and Entrepreneurship (2019)"],"keywords_ja":"神経多様性,ADHD,ASD,ディスレクシア,起業アドバンテージ","keywords_en":"neurodiversity,ADHD,autism,dyslexia,entrepreneurial advantage"},
  {"id":"inno_ent_400","name_ja":"スタートアップの事業計画書の役割","name_en":"Business Plan Role in Startups","definition":"事業計画書（ビジネスプラン）のスタートアップでの有用性をめぐる研究。Delmar & Shane（2003）は事業計画作成が新規ベンチャーの早期廃業を防ぐ効果を実証した一方、Kirschら（2009）は事業計画書とスタートアップ成功の相関が弱いことを示した。リーンスタートアップ運動により「計画より実行・検証」が主流化したが、資金調達・銀行融資では依然として事業計画が必要な制度的文脈も残る。","impact_summary":"起業家研究の実践的道具としての事業計画の役割を実証的に再評価し、状況依存的な活用論を提示した。","subfield":"entrepreneurship_venture","category":"A_foundations","school_of_thought":"実践的起業家方法論","era_start":2003,"schumpeter_layer":"ミクロ","innovation_type":"計画・経営ツールイノベーション","cognitive_mechanism":"明示的計画と不確実性管理の相互補完","key_researchers":["Frédéric Delmar","Scott Shane","Maxwell Wessel"],"key_works":["Does Business Planning Facilitate New Venture Development? (2003)","Why Business Plans Don't Deliver (2009)"],"keywords_ja":"事業計画書,ビジネスプラン,計画vs実行,リーンスタートアップ","keywords_en":"business plan,planning vs execution,lean startup,new venture development"},
]
conn = sqlite3.connect(DB)
